// ExecutePricingScriptWithContext executes a user-provided Lua script with a context for timeout control
func ExecutePricingScriptWithContext(ctx context.Context, script string, contextMap map[string]float64) (float64, error) {
	// Validate inputs
	if script == "" {
		return 0, fmt.Errorf("script cannot be empty")
	}

	if contextMap == nil {
		return 0, fmt.Errorf("context cannot be nil")
	}

	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Create a channel to receive the result
	type result struct {
		value float64
		err   error
	}
	resultChan := make(chan result, 1)

	// Execute the script in a goroutine with timeout control
	go func() {
		var res result

		defer func() {
			if r := recover(); r != nil {
				res.err = fmt.Errorf("lua script panicked: %v", r)
			}
			resultChan <- res
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			res.err = fmt.Errorf("failed to execute Lua script: %w", err)
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			res.err = fmt.Errorf("calculate_final_price is not a function or not defined")
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range contextMap {
			// Validate key to prevent injection attacks
			if k == "" {
				res.err = fmt.Errorf("context key cannot be empty")
				return
