		}

		L.ForEach(stringTable, func(key, value lua.LValue) {
			if keyStr, ok := key.(lua.LString); ok {
				if !allowedStringFuncs[string(keyStr)] {
					stringTable.RawSet(key, lua.LNil)
				}
			}
		})
	}

