	type execResult struct {
		value float64
		err   error
	}
	resultChan := make(chan execResult, 1)

	// Create a context with timeout
	execCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Set the context on the Lua state for timeout control
	L.SetContext(execCtx)

	go func() {
		defer func() {
			if r := recover(); r != nil {
				resultChan <- execResult{0, fmt.Errorf("lua execution panic: %v", r)}
			}
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			resultChan <- execResult{0, fmt.Errorf("failed to execute Lua script: %w", err)}
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			resultChan <- execResult{0, fmt.Errorf("calculate_final_price is not a function or not defined")}
			return
		}

