	"github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a Lua pricing script with the given context
// and returns the calculated final price as a float64.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Load and execute the Lua script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price function not found or is not a function")
	}

	// Create a Lua table for context variables
	ctxTable := L.NewTable()
	for key, value := range ctx {
		ctxTable.RawSet(lua.LString(key), lua.LNumber(value))
	}

	// Call the function with context table as argument
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the return value from the stack
	ret := L.Get(-1)
	L.Pop(1)

	// Convert the return value to float64
	result, ok := ret.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("calculate_final_price did not return a number, got %T", ret)
	}

	return float64(result), nil
}

func main() {
	// Example Lua pricing script
	script := `
function calculate_final_price(ctx)
    -- Apply 10% discount for VIP users (tier 2 or higher)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`

	// Context variables for the pricing calculation
	ctx := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}

	// Execute the pricing script
