package main

import (
	"context"
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

const (
	maxExecutionTime = 100 * time.Millisecond
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context with security restrictions.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Set up security restrictions
	setupSecureEnvironment(L)

	// Create a context with timeout for execution
	execCtx, cancel := context.WithTimeout(context.Background(), maxExecutionTime)
	defer cancel()

	// Set context for timeout checking during Lua execution
	L.SetContext(execCtx)

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		// Validate context values
		if v < 0 || v > 1e15 {
			return 0, fmt.Errorf("context value for %s is out of range", k)
		}
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	price := float64(result.(lua.LNumber))

	// Validate the result
	if price < 0 || price > 1e15 {
		return 0, fmt.Errorf("calculated price is out of valid range")
	}

	return price, nil
}

// setupSecureEnvironment configures the Lua state with security restrictions
func setupSecureEnvironment(L *lua.LState) {
	// Remove dangerous libraries
	dangerousLibs := []string{
		"os",
		"io",
		"debug",
		"package",
		"coroutine",
	}

	for _, lib := range dangerousLibs {
		L.SetGlobal(lib, lua.LNil)
	}

	// Restrict access to load functions that could execute arbitrary code
	L.SetGlobal("load", lua.LNil)
	L.SetGlobal("loadstring", lua.LNil)
	L.SetGlobal("loadfile", lua.LNil)
	L.SetGlobal("dofile", lua.LNil)

	// Keep only safe libraries
	safeLibs := []string{
		"string",
		"math",
		"table",
	}

	for _, lib := range safeLibs {
		if err := L.CallByParam(lua.P{
			Fn:      L.GetGlobal("require"),
			NRet:    1,
			Protect: true,
		}, lua.LString(lib)); err != nil {
			// Ignore errors for optional libraries
		}
	}
}

func main() {
	// Example usage
	script := `
function calculate_final_price(ctx)
    -- Apply 10% discount for VIP users (tier 2)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`

	ctx := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}

	price, err := ExecutePricingScript(script, ctx)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Final price: %.2f\n", price)
}

