	done := make(chan struct {
		result float64
		err    error
	}, 1)

	go func() {
		defer func() {
			if r := recover(); r != nil {
				done <- struct {
					result float64
					err    error
				}{0, fmt.Errorf("panic recovered: %v", r)}
